using System.Diagnostics;
using System.Runtime.CompilerServices;
using TextAnalysis;

string runtime = System.Runtime.InteropServices.RuntimeInformation.FrameworkDescription;
Console.WriteLine($"Runtime: {runtime}");
Console.WriteLine();

// Build sample text (~3300 words)
var words = new[] {
    "the", "quick", "brown", "fox", "jumps", "over", "the", "lazy", "dog",
    "a", "benchmark", "measures", "performance", "of", "code", "accurately",
    "dotnet", "runtime", "improvements", "are", "significant", "each", "release",
    "hello", "world", "this", "is", "a", "simple", "text", "analysis", "test"
};
var sb = new System.Text.StringBuilder();
for (int i = 0; i < 100; i++)
    foreach (var w in words)
        sb.Append(w).Append(' ');
string sampleText = sb.ToString();

var analyzer = new TextAnalyzer(sampleText);

// Warmup and benchmark helper
static (double medianNs, double[] allNs) Bench(Action action, int warmup = 500, int iterations = 10000)
{
    for (int i = 0; i < warmup; i++) action();

    // Run multiple rounds to get a stable median
    const int rounds = 5;
    double[] roundMedians = new double[rounds];
    double[] lastRoundNs = Array.Empty<double>();

    for (int r = 0; r < rounds; r++)
    {
        double[] times = new double[iterations];
        var sw = new Stopwatch();
        for (int i = 0; i < iterations; i++)
        {
            sw.Restart();
            action();
            sw.Stop();
            times[i] = sw.Elapsed.TotalNanoseconds;
        }
        Array.Sort(times);
        roundMedians[r] = times[iterations / 2];
        lastRoundNs = times;
    }
    Array.Sort(roundMedians);
    return (roundMedians[rounds / 2], lastRoundNs);
}

Console.WriteLine($"{"Method",-25} {"Median (ns)",15} {"P25 (ns)",12} {"P75 (ns)",12}");
Console.WriteLine(new string('-', 66));

var benchmarks = new (string Name, Action Act)[]
{
    ("AverageWordLength",  () => { var r = analyzer.AverageWordLength(); Consume(r); }),
    ("WordLengthHistogram", () => { var r = analyzer.WordLengthHistogram(); Consume(r); }),
    ("UniqueWordCount",    () => { var r = analyzer.UniqueWordCount(); Consume(r); }),
};

foreach (var (name, act) in benchmarks)
{
    var (median, all) = Bench(act);
    double p25 = all[all.Length / 4];
    double p75 = all[all.Length * 3 / 4];
    Console.WriteLine($"{name,-25} {median,15:F1} {p25,12:F1} {p75,12:F1}");
}

// Prevent dead-code elimination
[MethodImpl(MethodImplOptions.NoInlining)]
static void Consume<T>(T _) { }

